#include <stdio.h>

int divide(int a, int b, int* result) {
    if (b == 0) return -1; // Error code
    *result = a / b;
    return 0; // Success
}

int main() {
    int res;
    if (divide(10, 0, &res) != 0) {
        printf("Division failed\n");
    }
}

